53	-- Architecture
54	---------------------------------------------------------------------------------------------------
55	
56	architecture struct of olo_base_cc_bits is
57	
58	    -- Types
59	    type SyncStages_t is array(0 to SyncStages_g - 2) of std_logic_vector(Width_g - 1 downto 0);
60	
61	    -- Synchronizer registers
62	    signal RegIn : std_logic_vector(Width_g - 1 downto 0) := (others => '0');
63	    signal Reg0  : std_logic_vector(Width_g - 1 downto 0) := (others => '0');
64	    signal RegN  : SyncStages_t                           := (others => (others => '0'));
65	
66	    -- Synthesis attributes - shiftregister extraction
67	    attribute shreg_extract of Reg0  : signal is ShregExtract_SuppressExtraction_c;
68	    attribute shreg_extract of RegN  : signal is ShregExtract_SuppressExtraction_c;
69	    attribute shreg_extract of RegIn : signal is ShregExtract_SuppressExtraction_c;
70	
71	    attribute syn_srlstyle of Reg0  : signal is SynSrlstyle_FlipFlops_c;
72	    attribute syn_srlstyle of RegN  : signal is SynSrlstyle_FlipFlops_c;
73	    attribute syn_srlstyle of RegIn : signal is SynSrlstyle_FlipFlops_c;
74	
75	    -- Synthesis attributes - preserve registers
76	    attribute dont_merge of Reg0  : signal is DontMerge_SuppressChanges_c;
77	    attribute dont_merge of RegN  : signal is DontMerge_SuppressChanges_c;
78	    attribute dont_merge of RegIn : signal is DontMerge_SuppressChanges_c;
79	
80	    attribute preserve of Reg0  : signal is Preserve_SuppressChanges_c;
81	    attribute preserve of RegN  : signal is Preserve_SuppressChanges_c;
82	    attribute preserve of RegIn : signal is Preserve_SuppressChanges_c;
83	
84	    attribute syn_preserve of Reg0  : signal is SynPreserve_SuppressChanges_c;
85	    attribute syn_preserve of RegN  : signal is SynPreserve_SuppressChanges_c;
86	    attribute syn_preserve of RegIn : signal is SynPreserve_SuppressChanges_c;
87	
88	    attribute syn_keep of Reg0  : signal is SynKeep_SuppressChanges_c;
89	    attribute syn_keep of RegN  : signal is SynKeep_SuppressChanges_c;
90	    attribute syn_keep of RegIn : signal is SynKeep_SuppressChanges_c;
91	
92	    -- Synthesis attributes - async registers
93	    attribute async_reg of Reg0  : signal is AsyncReg_TreatAsync_c;
94	    attribute async_reg of RegN  : signal is AsyncReg_TreatAsync_c;
95	    attribute async_reg of RegIn : signal is AsyncReg_TreatAsync_c;
96	
97	    -- Input clock (required for automatic constraining in vivado)
98	    signal In_Clk_Sig : std_logic;
99	
100	    -- Synthesis attributes automatic constraining (AMD only)
101	    attribute dont_touch of In_Clk_Sig : signal is DontTouch_SuppressChanges_c;
102	    attribute keep of In_Clk_Sig       : signal is Keep_SuppressChanges_c;
103	
104	begin
105	
106	    In_Clk_Sig <= In_Clk;
107	
108	    -- Input Register
109	    p_inff : process (In_Clk) is
110	    begin
111	        if rising_edge(In_Clk) then
112	            RegIn <= In_Data;
113	            if In_Rst = '1' then
114	                RegIn <= (others => '0');
115	            end if;
116	        end if;
117	    end process;
118	
119	    -- Synchronizer process
120	    p_outff : process (Out_Clk) is
121	    begin
122	        if rising_edge(Out_Clk) then
123	            -- *** Synchronization ***
124	            -- First two stages
125	            Reg0    <= RegIn;
126	            RegN(0) <= Reg0;
127	
128	            -- Loop through aremaining stages
129	            for i in 1 to RegN'high loop
130	                RegN(i) <= RegN(i - 1);
131	            end loop;
132	
133	            -- *** Reset ***
134	            if Out_Rst = '1' then
135	                Reg0 <= (others => '0');
136	                RegN <= (others => (others => '0'));
137	            end if;
138	        end if;
139	    end process;
140	
141	    -- Output is content of last sync stage
142	    Out_Data <= RegN(RegN'high);
143	
